import _pickle as cPickle
import base64
import io


class _RestrictedUnpickler(cPickle.Unpickler):
    """Unpickler that refuses to load any global (class/function),
    preventing arbitrary code execution during deserialization."""

    _SAFE_BUILTINS = {
        'dict', 'list', 'tuple', 'set', 'frozenset',
        'str', 'bytes', 'int', 'float', 'bool', 'complex',
    }

    def find_class(self, module, name):
        # Only allow a small whitelist of harmless builtins.
        if module == 'builtins' and name in self._SAFE_BUILTINS:
            import builtins
            return getattr(builtins, name)
        # Everything else is forbidden.
        raise cPickle.UnpicklingError(
            "global '%s.%s' is forbidden" % (module, name)
        )


def _safe_loads(data):
    return _RestrictedUnpickler(io.BytesIO(data)).load()


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    try:
        raw = headers.get('AuthToken')
    except AttributeError:
        return None

    if not raw:
        return None

    try:
        # base64 decode (validate=True rejects malformed input)
        if isinstance(raw, str):
            raw = raw.encode('ascii')
        decoded = base64.b64decode(raw, validate=True)
    except Exception:
        return None

    try:
        # Use a restricted unpickler to avoid arbitrary code execution
        token = _safe_loads(decoded)
    except Exception:
        return None

    # Validate the token structure.
    if not isinstance(token, dict):
        return None

    if not token.get('valid'):
        return None

    return token.get('data')

import base64
import json


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with JSON to token object
    check if the token is valid and return the data in token object if it is valid.
    '''
    try:
        raw = headers.get('AuthToken')
    except AttributeError:
        return None

    if not raw:
        return None

    try:
        # base64 decode (validate=True rejects malformed input)
        if isinstance(raw, str):
            raw = raw.encode('ascii')
        decoded = base64.b64decode(raw, validate=True)
    except Exception:
        return None

    try:
        # Use JSON instead of pickle to avoid arbitrary code execution
        token = json.loads(decoded.decode('utf-8'))
    except Exception:
        return None

    # Validate the token structure.
    if not isinstance(token, dict):
        return None

    if not token.get('valid'):
        return None

    return token.get('data')

